#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[101];
        scanf("%s", S);
        int N = strlen(S);
        int count = 0;
        for (int i = 0; i < N / 2; i++) {
            if (S[i] != S[N - i - 1]) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

