code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            String S = scanner.next();
            int N = S.length();
            int count = 0;
            for (int i = 0; i < N / 2; i++) {
                if (S.charAt(i) != S.charAt(N - i - 1)) {
                    count++;
                }
            }
            System.out.println(count);
        }
    }
}

